function cosineSimilarity(a, b) {
  if (!Array.isArray(a) || !Array.isArray(b)) return 0;
  if (a.length !== b.length) return 0;

  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < a.length; i++) {
    const valA = Number(a[i]) || 0;
    const valB = Number(b[i]) || 0;

    dot += valA * valB;
    normA += valA * valA;
    normB += valB * valB;
  }

  // éviter division par 0
  if (normA === 0 || normB === 0) return 0;

  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
}

// Email entrant depuis Merge
const incomingNode = $('Merge').first();
if (!incomingNode || !incomingNode.json) {
  throw new Error("Données Merge introuvables");
}

const incoming = incomingNode.json;

// Embedding entrant
const incomingEmbedding =
  incoming.embedding ||
  (Array.isArray(incoming.embeddings) ? incoming.embeddings[0] : null);

if (!Array.isArray(incomingEmbedding)) {
  throw new Error("Embedding entrant invalide ou introuvable");
}

// Corpus
const fileItems = $('Extract from File').all();
const corpus = [];

for (const fileItem of fileItems) {
  const rows = fileItem.json?.data || [];

  for (const row of rows) {
    try {
      if (!row.line) continue;

      const mail = JSON.parse(row.line);

      if (Array.isArray(mail.embedding)) {
        corpus.push(mail);
      }
    } catch (e) {
      // optionnel : log erreur
      // console.log("Erreur parsing :", e);
    }
  }
}

// Calcul des scores
const results = corpus
  .filter(mail => mail.message_id !== incoming.message_id)
  .map(mail => ({
    json: {
      subject: mail.subject || "",
      body_text: mail.body_text || "",
      sender: mail.sender || "",
      similarity: cosineSimilarity(incomingEmbedding, mail.embedding)
    }
  }))
  .sort((a, b) => b.json.similarity - a.json.similarity)
  .slice(0, 3);

return results;
